<style>
.rp-page{max-width:1280px;margin:0 auto}.rp-hero{display:flex;justify-content:space-between;align-items:flex-start;gap:16px;margin-bottom:18px}.rp-hero h1{font-size:30px;margin:0;color:#0f172a}.rp-hero p{margin:6px 0 0;color:#64748b}.rp-actions{display:flex;gap:10px;flex-wrap:wrap}.rp-btn{display:inline-flex;align-items:center;justify-content:center;border:0;border-radius:12px;background:#111827;color:#fff;padding:10px 14px;font-weight:800;text-decoration:none;cursor:pointer}.rp-btn.secondary{background:#f0fdf4;color:#166534}.rp-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px;margin-bottom:18px}.rp-stat{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:16px}.rp-stat span{display:block;color:#64748b;font-size:12px;text-transform:uppercase;font-weight:800}.rp-stat strong{display:block;font-size:26px;color:#0f172a}.rp-card{background:#fff;border:1px solid #e5e7eb;border-radius:20px;overflow:hidden;margin-bottom:18px}.rp-card-header{padding:16px;border-bottom:1px solid #edf2f7;display:flex;justify-content:space-between;gap:10px;align-items:center}.rp-card-header h2{margin:0;font-size:18px}.rp-form{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px;padding:16px;border-bottom:1px solid #edf2f7}.rp-form input,.rp-form select,.rp-form textarea{border:1px solid #d8dee9;border-radius:12px;padding:10px 12px;width:100%}.rp-form textarea{grid-column:span 2}.rp-table{width:100%;border-collapse:collapse}.rp-table th{background:#f8fafc;color:#64748b;font-size:12px;text-transform:uppercase;text-align:left;padding:13px}.rp-table td{border-top:1px solid #edf2f7;padding:13px;vertical-align:top}.rp-badge{display:inline-flex;border-radius:999px;padding:4px 9px;font-size:12px;font-weight:800;background:#f1f5f9;color:#475569}.rp-badge.paid,.rp-badge.completed,.rp-badge.ready,.rp-badge.active{background:#dcfce7;color:#166534}.rp-badge.received,.rp-badge.diagnosing,.rp-badge.repairing{background:#fef3c7;color:#92400e}.rp-badge.cancelled,.rp-badge.failed{background:#fee2e2;color:#991b1b}.rp-muted{color:#64748b;font-size:13px}.rp-empty{padding:34px;text-align:center;color:#64748b}.rp-pagination{padding:14px;border-top:1px solid #edf2f7}.rp-alert{background:#dcfce7;color:#166534;border:1px solid #bbf7d0;border-radius:12px;padding:10px 14px;margin-bottom:14px;font-weight:700}@media(max-width:1000px){.rp-grid{grid-template-columns:repeat(2,1fr)}.rp-form{grid-template-columns:1fr}.rp-form textarea{grid-column:auto}.rp-table{display:block;overflow:auto}.rp-hero{display:block}}
</style>
